<content>import { useCallback, useMemo } from 'react';
import { useNavigate } from 'react-router-dom';
import { SidebarItemT } from 'Types/SidebarItemT';
import styles from './SidebarItem.module.scss';

export type PropsT = {
  item: SidebarItemT;
  onItemClick?: (itemId: string) => void;
};

export const SidebarItem = (props: PropsT) => {
  const navigate = useNavigate();

  const itemClassName = useMemo(() => {
    const classes = [styles.sidebarItem];
    if (props.item.isActive) {
      classes.push(styles.active);
    }
    return classes.join(' ');
  }, [props.item.isActive]);

  const handleClick = useCallback(() => {
    if (props.onItemClick) {
      props.onItemClick(props.item.id);
    }
    navigate(props.item.path);
  }, [props.onItemClick, props.item.id, props.item.path, navigate]);

  return (
    <button
      type="button"
      className={itemClassName}
      onClick={handleClick}
      aria-label={props.item.label}
      aria-current={props.item.isActive ? 'page' : undefined}
    >
      <span className={styles.icon} data-icon={props.item.icon} />
      <span className={styles.label}>{props.item.label}</span>
    </button>
  );
};
</content>
