<content>import { useCallback, useMemo } from 'react';
import { useLocation } from 'react-router-dom';
import { SidebarItem } from './SidebarItem';
import { SidebarItemT } from 'Types/SidebarItemT';
import { NavigationIconE } from 'Types/NavigationIconE';
import styles from './Sidebar.module.scss';

export type PropsT = {
  isOpen: boolean;
  onClose: () => void;
  onItemClick?: (itemId: string) => void;
};

export const Sidebar = (props: PropsT) => {
  const location = useLocation();

  const navigationItems = useMemo<SidebarItemT[]>(
    () => [
      {
        id: 'dashboard',
        label: 'Dashboard',
        icon: NavigationIconE.Dashboard,
        path: '/dashboard',
        isActive: location.pathname === '/dashboard',
      },
      {
        id: 'budget',
        label: 'Budget',
        icon: NavigationIconE.Budget,
        path: '/budget',
        isActive: location.pathname === '/budget',
      },
      {
        id: 'transactions',
        label: 'Transactions',
        icon: NavigationIconE.Transactions,
        path: '/transactions',
        isActive: location.pathname === '/transactions',
      },
      {
        id: 'reports',
        label: 'Reports',
        icon: NavigationIconE.Reports,
        path: '/reports',
        isActive: location.pathname === '/reports',
      },
      {
        id: 'settings',
        label: 'Settings',
        icon: NavigationIconE.Settings,
        path: '/settings',
        isActive: location.pathname === '/settings',
      },
      {
        id: 'help',
        label: 'Help',
        icon: NavigationIconE.Help,
        path: '/help',
        isActive: location.pathname === '/help',
      },
    ],
    [location.pathname],
  );

  const sidebarClassName = useMemo(() => {
    const classes = [styles.sidebar];
    if (props.isOpen) {
      classes.push(styles.open);
    }
    return classes.join(' ');
  }, [props.isOpen]);

  const handleOverlayClick = useCallback(() => {
    props.onClose();
  }, [props.onClose]);

  const handleItemClick = useCallback(
    (itemId: string) => {
      if (props.onItemClick) {
        props.onItemClick(itemId);
      }
      props.onClose();
    },
    [props.onItemClick, props.onClose],
  );

  return (
    <>
      <div
        className={styles.overlay}
        onClick={handleOverlayClick}
        aria-hidden={!props.isOpen}
        style={{ display: props.isOpen ? 'block' : 'none' }}
      />
      <aside className={sidebarClassName} aria-label="Main navigation">
        <nav className={styles.navigation}>
          <ul className={styles.navigationList}>
            {navigationItems.map((item) => (
              <li key={item.id} className={styles.navigationItem}>
                <SidebarItem item={item} onItemClick={handleItemClick} />
              </li>
            ))}
          </ul>
        </nav>
      </aside>
    </>
  );
};
</content>
