<content>import { describe, it, expect } from 'vitest';
import { renderHook, act } from '@testing-library/react';
import { useSidebar } from '../useSidebar';

describe('useSidebar', () => {
  it('initializes with closed state', () => {
    const { result } = renderHook(() => useSidebar());

    expect(result.current.isOpen).toBe(false);
  });

  it('opens sidebar when openSidebar is called', () => {
    const { result } = renderHook(() => useSidebar());

    act(() => {
      result.current.openSidebar();
    });

    expect(result.current.isOpen).toBe(true);
  });

  it('closes sidebar when closeSidebar is called', () => {
    const { result } = renderHook(() => useSidebar());

    act(() => {
      result.current.openSidebar();
    });

    expect(result.current.isOpen).toBe(true);

    act(() => {
      result.current.closeSidebar();
    });

    expect(result.current.isOpen).toBe(false);
  });

  it('toggles sidebar state when toggleSidebar is called', () => {
    const { result } = renderHook(() => useSidebar());

    expect(result.current.isOpen).toBe(false);

    act(() => {
      result.current.toggleSidebar();
    });

    expect(result.current.isOpen).toBe(true);

    act(() => {
      result.current.toggleSidebar();
    });

    expect(result.current.isOpen).toBe(false);
  });

  it('maintains state after multiple operations', () => {
    const { result } = renderHook(() => useSidebar());

    act(() => {
      result.current.openSidebar();
    });
    expect(result.current.isOpen).toBe(true);

    act(() => {
      result.current.openSidebar();
    });
    expect(result.current.isOpen).toBe(true);

    act(() => {
      result.current.closeSidebar();
    });
    expect(result.current.isOpen).toBe(false);

    act(() => {
      result.current.closeSidebar();
    });
    expect(result.current.isOpen).toBe(false);
  });

  it('provides stable function references', () => {
    const { result, rerender } = renderHook(() => useSidebar());

    const initialOpenSidebar = result.current.openSidebar;
    const initialCloseSidebar = result.current.closeSidebar;
    const initialToggleSidebar = result.current.toggleSidebar;

    rerender();

    expect(result.current.openSidebar).toBe(initialOpenSidebar);
    expect(result.current.closeSidebar).toBe(initialCloseSidebar);
    expect(result.current.toggleSidebar).toBe(initialToggleSidebar);
  });
});
