<content>import { useCallback, useMemo } from 'react';
import { NavLink } from 'react-router-dom';
import styles from './Sidebar.module.scss';

export type PropsT = {
  isCollapsed: boolean;
  onToggle: () => void;
};

type NavItemT = {
  path: string;
  icon: string;
  label: string;
};

export const Sidebar = (props: PropsT) => {
  const navItems: NavItemT[] = useMemo(
    () => [
      { path: '/dashboard', icon: '📊', label: 'Dashboard' },
      { path: '/transactions', icon: '💳', label: 'Transactions' },
      { path: '/budgets', icon: '💰', label: 'Budgets' },
      { path: '/categories', icon: '🏷️', label: 'Categories' },
      { path: '/reports', icon: '📈', label: 'Reports' },
      { path: '/settings', icon: '⚙️', label: 'Settings' },
    ],
    []
  );

  const handleToggle = useCallback(() => {
    props.onToggle();
  }, [props]);

  const sidebarClassName = useMemo(
    () => `${styles.sidebar} ${props.isCollapsed ? styles.collapsed : ''}`,
    [props.isCollapsed]
  );

  return (
    <aside className={sidebarClassName}>
      <button
        type="button"
        className={styles.toggleButton}
        onClick={handleToggle}
        aria-label={props.isCollapsed ? 'Expand sidebar' : 'Collapse sidebar'}
        aria-expanded={!props.isCollapsed}
      >
        <span className={styles.toggleIcon}>
          {props.isCollapsed ? '→' : '←'}
        </span>
      </button>

      <nav className={styles.nav} aria-label="Main navigation">
        <ul className={styles.navList}>
          {navItems.map((item) => (
            <li key={item.path} className={styles.navItem}>
              <NavLink
                to={item.path}
                className={({ isActive }) =>
                  `${styles.navLink} ${isActive ? styles.active : ''}`
                }
                aria-label={item.label}
              >
                <span className={styles.icon} aria-hidden="true">
                  {item.icon}
                </span>
                {!props.isCollapsed && (
                  <span className={styles.label}>{item.label}</span>
                )}
              </NavLink>
            </li>
          ))}
        </ul>
      </nav>
    </aside>
  );
};
</content>
</write_file>

