<content>import { AxiosError } from 'axios';
import { ApiError } from 'Shared/errors/ApiError';
import { modalService } from 'Services/modalService';
import { ModalNameE } from 'Components/modal/ModalNameE';

const handleErrorModal = (error: AxiosError): void => {
  const message =
    (error.response?.data as { message?: string })?.message ||
    error.message ||
    'Something went wrong. Please try again.';

  modalService.open(ModalNameE.ERROR, { message });
};

export const errorInterceptor = (error: AxiosError): Promise<never> => {
  handleErrorModal(error);

  const apiError = new ApiError(
    error.message,
    error.response?.status,
    error,
  );

  return Promise.reject(apiError);
};
</content>
</write_file>

