<content>import { useMemo } from 'react';
import { Modal } from 'Components/modal/Modal';
import { ModalNameE } from 'Components/modal/ModalNameE';
import { useModal } from 'Services/modalService';
import './errorModal.css';

export const ErrorModal = () => {
  const { modals, close } = useModal();

  const errorModal = useMemo(
    () => modals.find((modal) => modal.name === ModalNameE.ERROR),
    [modals],
  );

  const handleClose = () => {
    if (errorModal) {
      close(errorModal.id);
    }
  };

  if (!errorModal) {
    return null;
  }

  return (
    <Modal isOpen={true} onClose={handleClose}>
      <div className="error-modal">
        <div className="error-modal__header">
          <h2 className="error-modal__title">Error</h2>
        </div>
        <div className="error-modal__content">
          <p className="error-modal__message">{errorModal.props.message}</p>
        </div>
        <div className="error-modal__footer">
          <button className="error-modal__button" onClick={handleClose}>
            Close
          </button>
        </div>
      </div>
    </Modal>
  );
};
</content>
