import { AxiosError } from 'axios';

import { modalService } from 'Services/modalService';
import { ModalNameE } from 'Components/modal/ModalNameE';

const FALLBACK_ERROR_MESSAGE = 'Something went wrong. Please try again.';

const extractErrorMessage = (error: AxiosError): string => {
  const responseData = error.response?.data as
    | { message?: string; errors?: Array<{ msg?: string }> }
    | undefined;

  if (responseData?.message && typeof responseData.message === 'string') {
    return responseData.message;
  }

  if (responseData?.errors?.[0]?.msg) {
    return responseData.errors[0].msg;
  }

  return FALLBACK_ERROR_MESSAGE;
};

export const handleErrorModal = (error: AxiosError): void => {
  const message = extractErrorMessage(error);

  modalService.open(ModalNameE.ERROR, { message });
};

