import React, { useCallback } from 'react';

import './errorModal.css';

import Modal from 'Components/modal/Modal';
import { ModalNameE } from 'Components/modal/ModalNameE';
import { ModalTypeE } from 'Components/modal/ModalTypeE';
import { useModalData } from 'Components/modal/useModalData';
import { modalService } from 'Services/modalService';

const ErrorModal = () => {
  const modalData = useModalData(ModalNameE.ERROR);

  const handleClose = useCallback(() => {
    modalService.close(ModalNameE.ERROR);
  }, []);

  return (
    <Modal
      name={ModalNameE.ERROR}
      title="Error"
      type={ModalTypeE.ERROR}
    >
      <p
        className="error-modal__message"
        role="alert"
        aria-live="assertive"
      >
        {modalData.props?.message}
      </p>

      <button
        className="error-modal__close-button"
        onClick={handleClose}
        type="button"
        aria-label="Close error dialog"
      >
        Close
      </button>
    </Modal>
  );
};

export default ErrorModal;

.modal--error {
  border: 2px solid var(--color-error, #dc3545);
}

.modal--error h2 {
  color: var(--color-error, #dc3545);
}

.error-modal__message {
  margin: 16px 0;
  color: var(--color-text, #333);
  font-size: 14px;
  line-height: 1.5;
}

.error-modal__close-button {
  display: block;
  width: 100%;
  padding: 12px 24px;
  background-color: var(--color-error, #dc3545);
  color: var(--color-white, #fff);
  border: none;
  border-radius: 4px;
  font-size: 14px;
  font-weight: 500;
  cursor: pointer;
  transition: background-color 0.2s ease;
}

.error-modal__close-button:hover {
  background-color: var(--color-error-dark, #c82333);
}

.error-modal__close-button:focus {
  outline: 2px solid var(--color-error, #dc3545);
  outline-offset: 2px;
}

