import { createGlobalValueSetter } from 'Shared/store/createGlobalValueSetter';
import { ModalNameE } from 'Components/modal/ModalNameE';

import { modalService } from './modalService';
import { Mock } from 'vitest';

vi.mock('Shared/store/createGlobalValueSetter', () => ({
  createGlobalValueSetter: vi.fn(() => vi.fn()),
}));

describe('modalService', () => {
  let mockUpdateModals: Mock;

  beforeAll(() => {
    const factoryMock = createGlobalValueSetter as Mock;
    mockUpdateModals = factoryMock.mock.results[0].value;
  });

  beforeEach(() => {
    mockUpdateModals.mockClear();
  });

  describe('open', () => {
    it('should call the updater and prepend the new modal to the list', () => {
      const modalName = 'TEST_MODAL' as ModalNameE;
      const modalProps = { id: 123 };

      // @ts-expect-error just for testing
      const result = modalService.open(modalName, modalProps);

      expect(result).toBe(modalName);
      expect(mockUpdateModals).toHaveBeenCalledTimes(1);

      const updateCallback = mockUpdateModals.mock.calls[0][0];

      const currentModals = [
        {
          name: 'OTHER_MODAL',
          props: {},
          deleted: false,
        },
      ];

      const newState = updateCallback(currentModals);

      expect(newState).toHaveLength(2);
      expect(newState[0]).toEqual({
        deleted: false,
        name: modalName,
        props: modalProps,
      });
      expect(newState[1]).toBe(currentModals[0]);
    });

    it('should handle opening a modal without props', () => {
      const modalName = 'TEST_MODAL' as ModalNameE;

      modalService.open(modalName);

      const updateCallback = mockUpdateModals.mock.calls[0][0];
      const newState = updateCallback([]);

      expect(newState[0]).toEqual({
        deleted: false,
        name: modalName,
        props: undefined,
      });
    });
  });

  describe('close', () => {
    it('should call the updater and filter out the modal by name', () => {
      const modalToClose = 'TEST_MODAL' as ModalNameE;
      const modalToKeep = 'OTHER_MODAL' as ModalNameE;

      modalService.close(modalToClose);

      expect(mockUpdateModals).toHaveBeenCalledTimes(1);

      const updateCallback = mockUpdateModals.mock.calls[0][0];

      const currentModals = [
        {
          name: modalToClose,
          props: {},
          deleted: false,
        },
        {
          name: modalToKeep,
          props: {},
          deleted: false,
        },
      ];

      const newState = updateCallback(currentModals);

      expect(newState).toHaveLength(1);
      expect(newState[0].name).toBe(modalToKeep);
      expect(
        newState.find((m: { name: string }) => m.name === modalToClose),
      ).toBeUndefined();
    });
  });
});

