import { AxiosError, AxiosHeaders } from 'axios';

import { modalService } from 'Services/modalService';
import { ModalNameE } from 'Components/modal/ModalNameE';

import { handleErrorModal } from './errorInterceptor';

vi.mock('Services/modalService');

describe('errorInterceptor', () => {
  const mockModalService = modalService as {
    open: ReturnType<typeof vi.fn>;
  };

  beforeEach(() => {
    mockModalService.open = vi.fn();
  });

  afterEach(() => {
    vi.clearAllMocks();
  });

  const createAxiosError = (
    responseData?: Record<string, unknown>,
  ): AxiosError => {
    return {
      isAxiosError: true,
      name: 'AxiosError',
      message: 'Request failed',
      toJSON: () => ({}),
      response: responseData
        ? {
            data: responseData,
            status: 500,
            statusText: 'Internal Server Error',
            headers: {},
            config: {
              headers: new AxiosHeaders(),
            },
          }
        : undefined,
      config: {
        headers: new AxiosHeaders(),
      },
    };
  };

  describe('handleErrorModal', () => {
    it('should open error modal with message from response.data.message', () => {
      const error = createAxiosError({ message: 'Server error occurred' });

      handleErrorModal(error);

      expect(mockModalService.open).toHaveBeenCalledWith(ModalNameE.ERROR, {
        message: 'Server error occurred',
      });
    });

    it('should open error modal with message from response.data.errors[0].msg', () => {
      const error = createAxiosError({
        errors: [{ msg: 'First error message' }],
      });

      handleErrorModal(error);

      expect(mockModalService.open).toHaveBeenCalledWith(ModalNameE.ERROR, {
        message: 'First error message',
      });
    });

    it('should use fallback message when no response data', () => {
      const error = createAxiosError();

      handleErrorModal(error);

      expect(mockModalService.open).toHaveBeenCalledWith(ModalNameE.ERROR, {
        message: 'Something went wrong. Please try again.',
      });
    });

    it('should use fallback message when response data has no message or errors', () => {
      const error = createAxiosError({ someOtherField: 'value' });

      handleErrorModal(error);

      expect(mockModalService.open).toHaveBeenCalledWith(ModalNameE.ERROR, {
        message: 'Something went wrong. Please try again.',
      });
    });

    it('should use fallback message when errors array is empty', () => {
      const error = createAxiosError({ errors: [] });

      handleErrorModal(error);

      expect(mockModalService.open).toHaveBeenCalledWith(ModalNameE.ERROR, {
        message: 'Something went wrong. Please try again.',
      });
    });

    it('should prefer message field over errors array', () => {
      const error = createAxiosError({
        message: 'Primary message',
        errors: [{ msg: 'Secondary message' }],
      });

      handleErrorModal(error);

      expect(mockModalService.open).toHaveBeenCalledWith(ModalNameE.ERROR, {
        message: 'Primary message',
      });
    });
  });
});

