import axios from 'axios';

import { ValidationError } from 'Shared/errors/ValidationError';
import { AuthorizationError } from 'Shared/errors/AuthorizationError';
import { LocalStorageNameE } from 'Services/localStorage/types/LocalStorageNameE';
import { authService } from 'Services/authService';
import { localStorageService } from 'Services/localStorage/localStorageService';
import { handleErrorModal } from 'Shared/requestClient/errorInterceptor';

export const axiosClient = axios.create({
  baseURL: process.env.VITE_APP_API_BASE_URL,
  headers: {
    'Content-Type': 'application/json',
  },
  timeout: 10000,
  withCredentials: false,
});

axiosClient.interceptors.request.use(
  config => {
    const token = localStorageService.get(LocalStorageNameE.ACCESS_TOKEN);

    if (token) {
      config.headers['Authorization'] = token;
    }

    return config;
  },
  error => Promise.reject(error),
);

axiosClient.interceptors.response.use(
  response => response,
  error => {
    if (
      error.response?.status === 400 &&
      error.response.data?.errors?.length > 0
    ) {
      const validationError = new ValidationError(error.response.data.errors);

      return Promise.reject(validationError);
    }

    if (error.response?.status === 401) {
      authService.logout();

      const authorizationError = new AuthorizationError(
        error.response.data?.errors?.[0]?.msg || 'Unauthorized',
      );

      return Promise.reject(authorizationError);
    }

    handleErrorModal(error);

    return Promise.reject(error);
  },
);
```

