// Read on page load
const language = cookieService.get(CookieNameE.LANGUAGE) || 'en';

// Clear on logout
cookieService.remove(CookieNameE.SESSION_ID);
```

**Dependencies:** `universal-cookie`

---

## Service Patterns

### Pattern 1: Global State Services

Services that manage global state using signals.

**Services:** `authService`, `modalService`, `sidebarService`, `notificationService`

**Pattern:**

```typescript
import { createGlobalValueSetter } from 'Shared/store/createGlobalValueSetter';
import { GlobalStoreFieldE } from 'Shared/types/GlobalStoreFieldE';

const updateField = createGlobalValueSetter(GlobalStoreFieldE.MY_FIELD);

export const myService = {
  add: item => {
    updateField(current => [...current, item]);
  },
  remove: id => {
    updateField(current => current.filter(i => i.id !== id));
  },
};
```

**Why:**

- Centralized state management
- Type-safe updates
- Reactive - components re-render automatically
- Service logic separated from UI

---

### Pattern 2: Storage Services

Services that wrap browser storage APIs with type safety.

**Services:** `localStorageService`, `cookieService`

**Pattern:**

```typescript
export const storageService = {
  set<T extends KeyEnum>(name: T, value: TypeMap[T]) {
    // Type-safe set
  },
  get<T extends KeyEnum>(name: T): TypeMap[T] | null {
    // Type-safe get with return type inference
  },
  remove<T extends KeyEnum>(name: T) {
    // Type-safe remove
  },
};
```

**Benefits:**

- TypeScript ensures correct types for each key
- Centralized storage logic
- Easy to add new storage keys
- Consistent error handling

---

### Pattern 3: API Services

Services that wrap API calls with error handling.

**Services:** `aiAssistantService`

**Pattern:**

```typescript
export const apiService = {
  async operation(params): Promise<ResultT> {
    try {
      const response = await axiosClient.post(endpoint, params);
      return response.data;
    } catch (error) {
      if (error instanceof AxiosError) {
        // Handle specific errors
        if (error.code === 'ECONNABORTED') {
          throw new Error('User-friendly message');
        }
      }
      throw error; // Re-throw unknown errors
    }
  },
};
```

**Benefits:**

- Consistent error handling
- User-friendly error messages
- Timeout handling
- Type-safe responses

---

## Error Handling

### General Principles

1. **Catch at service level** - Services should catch and transform errors
2. **User-friendly messages** - Convert technical errors to readable messages
3. **Log for debugging** - Console errors in development
4. **Graceful degradation** - Return sensible defaults when possible

### Examples

**Storage Services:**

```typescript
try {
  return JSON.parse(data);
} catch {
  // Remove corrupted data and return null
  localStorage.removeItem(key);
  return null;
}
```

**API Services:**

```typescript
catch (error: unknown) {
  if (error instanceof AxiosError) {
    if (error.code === 'ECONNABORTED') {
      throw new Error('Request timed out');
    }
    if (error.response?.status === 500) {
      throw new Error('Server error');
    }
  }
  throw error; // Unknown errors re-thrown
}
```

**Notification:**

```typescript
try {
  await riskyOperation();
  notificationService.addAlert('Success!');
} catch (error) {
  notificationService.addErrorAlert(error.message);
}
```

---

## Testing Services

Services should have tests in `__tests__` directories:

```
src/services/
  ├── authService.ts
  ├── authService.test.ts
  ├── modalService.ts
  └── modalService.test.ts
```

**Test Guidelines:**

- Test each public method
- Test error cases
- Mock dependencies (storage, API calls)
- Test state changes for state-management services

**Example:**

```typescript
describe('authService', () => {
  it('should initialize with token from localStorage', () => {
    localStorageService.set(LocalStorageNameE.ACCESS_TOKEN, 'token-123');

    authService.initialize();

    expect(globalStore[GlobalStoreFieldE.AUTH_TOKEN].value).toBe('token-123');
  });

  it('should clear cache on logout', () => {
    authService.logout();

    expect(queryClient.clear).toHaveBeenCalled();
  });
});
```

---

## Service Dependencies

```
authService
  ├── localStorageService
  ├── globalStore
  ├── queryClient
  └── sentryHelpers

modalService
  └── globalStore

sidebarService
  └── globalStore

notificationService
  └── globalStore

scrollLockService
  └── (none - pure DOM)

aiAssistantService
  └── axiosClient

aiConversationStorageService
  └── localStorageService

localStorageService
  └── jsonHelpers

cookieService
  └── universal-cookie (external)
```

