  ├── localStorageService
  ├── globalStore
  ├── queryClient
  └── sentryHelpers

modalService
  └── globalStore

sidebarService
  └── globalStore

notificationService
  └── globalStore

scrollLockService
  └── (none - pure DOM)

aiAssistantService
  └── axiosClient

aiConversationStorageService
  └── localStorageService

localStorageService
  └── jsonHelpers

cookieService
  └── universal-cookie (external)
```

